import { execSync } from 'child_process';
import { writeFileSync, mkdirSync, existsSync } from 'fs';
import { join } from 'path';

const BASE = 'https://coding-alive.jp';
const UA = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) Chrome/120.0.0.0';
const visited = new Set();
const queue = [BASE + '/'];
const pages = new Map();
const cacheDir = join(import.meta.dirname, 'cache');

if (!existsSync(cacheDir)) mkdirSync(cacheDir, { recursive: true });

function normalize(u) {
  try {
    const parsed = new URL(u, BASE);
    if (parsed.hostname !== 'coding-alive.jp') return null;
    let path = parsed.pathname || '/';
    if (/\.(pdf|jpg|jpeg|png|gif|svg|webp|mp4|zip|css|js|woff2?|ttf|ico)$/i.test(path)) return null;
    if (path.includes('/wp-admin') || path.includes('/wp-content') || path.includes('/assets/')) return null;
    if (!path.endsWith('/') && !/\.[a-z0-9]+$/i.test(path) && !path.includes('/p')) {
      // keep trailing slash for dirs except post slugs like /work/p123/
    }
    return parsed.origin + path;
  } catch {
    return null;
  }
}

function fetch(url) {
  const key = url.replace(/[^a-z0-9]+/gi, '_').slice(0, 120);
  const file = join(cacheDir, key + '.html');
  try {
    execSync(
      `curl.exe -sL -A "${UA}" "${url}" -o "${file}" -w "%{http_code}"`,
      { encoding: 'utf8', timeout: 30000 }
    );
    const status = execSync(`curl.exe -sL -A "${UA}" "${url}" -o NUL -w "%{http_code}"`, {
      encoding: 'utf8',
      timeout: 30000,
    }).trim();
    if (!existsSync(file)) return null;
    const html = require('fs').readFileSync(file, 'utf8');
    return { status: Number(status) || 200, html };
  } catch (e) {
    return null;
  }
}

function extractLinks(html) {
  const found = [];
  const re = /href=["']([^"'#]+)["']/gi;
  let m;
  while ((m = re.exec(html)) !== null) {
    const n = normalize(m[1]);
    if (n) found.push(n);
  }
  return found;
}

function extractTitle(html) {
  const m = html.match(/<title[^>]*>([^<]+)<\/title>/i);
  return m ? m[1].trim() : '';
}

async function crawl() {
  while (queue.length > 0 && visited.size < 300) {
    const key = normalize(queue.shift());
    if (!key || visited.has(key)) continue;
    visited.add(key);
    const result = fetch(key);
    if (!result || result.status !== 200) {
      console.log('SKIP', key, result?.status);
      continue;
    }
    const title = extractTitle(result.html);
    pages.set(key, { title });
    const found = extractLinks(result.html);
    for (const l of found) {
      if (!visited.has(l) && !queue.includes(l)) queue.push(l);
    }
    console.log('OK', visited.size, key);
  }

  const sorted = [...pages.entries()].sort((a, b) => a[0].localeCompare(b[0]));
  const manifest = sorted.map(([url, info]) => {
    const path = new URL(url).pathname;
    let pageType = 'static';
    let parent = '/';
    let template = 'static-page';

    if (path === '/' || path === '') {
      pageType = 'home';
      template = 'home';
    } else if (path === '/work/' || path === '/work') {
      pageType = 'archive';
      template = 'work-archive';
    } else if (path.match(/^\/work\/p\d+\/?$/)) {
      pageType = 'detail';
      parent = '/work/';
      template = 'work-detail';
    } else if (path.startsWith('/work/')) {
      pageType = 'category';
      parent = '/work/';
      template = 'work-category';
    } else if (path === '/animation/' || path === '/animation') {
      pageType = 'archive';
      template = 'animation-archive';
    } else if (path.match(/^\/animation\/p\d+\/?$/)) {
      pageType = 'detail';
      parent = '/animation/';
      template = 'animation-detail';
    } else if (path.startsWith('/animation/')) {
      pageType = 'category';
      parent = '/animation/';
      template = 'animation-category';
    } else if (path === '/blog/' || path === '/blog') {
      pageType = 'archive';
      template = 'blog-archive';
    } else if (path.match(/^\/blog\/p\d+\/?$/)) {
      pageType = 'detail';
      parent = '/blog/';
      template = 'blog-detail';
    } else if (path.startsWith('/blogcat/')) {
      pageType = 'category';
      parent = '/blog/';
      template = 'blog-category';
    }

    return {
      source_url: url,
      local_route: path.endsWith('/') && path !== '/' ? path.slice(0, -1) || '/' : path || '/',
      page_title: info.title,
      page_type: pageType,
      parent_page: parent,
      template_used: template,
    };
  });

  writeFileSync(join(import.meta.dirname, 'route-manifest.json'), JSON.stringify(manifest, null, 2));
  console.log('\n=== TOTAL:', manifest.length, '===');
  for (const r of manifest) {
    console.log(r.local_route + '\t' + r.page_type + '\t' + r.page_title.slice(0, 50));
  }
}

crawl();

$ErrorActionPreference = 'SilentlyContinue'
$Base = 'https://coding-alive.jp'
$UA = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) Chrome/120.0.0.0'
$CacheDir = Join-Path $PSScriptRoot 'cache'
New-Item -ItemType Directory -Force -Path $CacheDir | Out-Null

$visited = @{}
$queue = @("$Base/")
$pages = @{}

function Normalize-Url($u) {
  try {
    $parsed = [Uri]$u
    if ($parsed.Host -ne 'coding-alive.jp') { return $null }
    $path = $parsed.AbsolutePath
    if ($path -match '\.(pdf|jpg|jpeg|png|gif|svg|webp|mp4|zip|css|js|woff2?|ttf|ico)$') { return $null }
    if ($path -match '/wp-content|/assets/|/wp-admin') { return $null }
    return "$($parsed.Scheme)://$($parsed.Host)$path"
  } catch { return $null }
}

function Get-PageType($path) {
  if ($path -eq '/' -or $path -eq '') { return @{ type='home'; parent='/'; template='home' } }
  if ($path -eq '/work/') { return @{ type='archive'; parent='/'; template='work-archive' } }
  if ($path -match '^/work/p\d+/?$') { return @{ type='detail'; parent='/work/'; template='work-detail' } }
  if ($path -match '^/work/') { return @{ type='category'; parent='/work/'; template='work-category' } }
  if ($path -eq '/animation/') { return @{ type='archive'; parent='/'; template='animation-archive' } }
  if ($path -match '^/animation/p\d+/?$') { return @{ type='detail'; parent='/animation/'; template='animation-detail' } }
  if ($path -match '^/animation/') { return @{ type='category'; parent='/animation/'; template='animation-category' } }
  if ($path -eq '/blog/') { return @{ type='archive'; parent='/'; template='blog-archive' } }
  if ($path -match '^/blog/p\d+/?$') { return @{ type='detail'; parent='/blog/'; template='blog-detail' } }
  if ($path -match '^/blogcat/') { return @{ type='category'; parent='/blog/'; template='blog-category' } }
  $static = @{
    '/our-strength/' = 'our-strength'
    '/services/' = 'services'
    '/fee/' = 'fee'
    '/faq/' = 'faq'
    '/staff/' = 'staff'
    '/company/' = 'company'
    '/contact/' = 'contact'
    '/privacy/' = 'privacy'
  }
  foreach ($k in $static.Keys) {
    if ($path -eq $k) { return @{ type='static'; parent='/'; template=$static[$k] } }
  }
  return @{ type='static'; parent='/'; template='static-page' }
}

$count = 0
while ($queue.Count -gt 0 -and $count -lt 350) {
  $url = $queue[0]
  $queue = $queue[1..($queue.Length-1)]
  $key = Normalize-Url $url
  if (-not $key -or $visited.ContainsKey($key)) { continue }
  $visited[$key] = $true
  $count++

  $safe = ($key -replace '[^a-zA-Z0-9]', '_').Substring(0, [Math]::Min(80, ($key -replace '[^a-zA-Z0-9]', '_').Length))
  $file = Join-Path $CacheDir "$safe.html"
  $null = curl.exe -sL -A $UA $key -o $file -w "%{http_code}" 2>$null
  if (-not (Test-Path $file) -or (Get-Item $file).Length -lt 500) {
    Write-Host "SKIP $key"
    continue
  }
  $html = Get-Content $file -Raw -Encoding UTF8
  $title = ''
  if ($html -match '<title[^>]*>([^<]+)</title>') { $title = $matches[1].Trim() }
  $pages[$key] = $title
  Write-Host "OK $count $key"

  $matches = [regex]::Matches($html, 'href="(https://coding-alive\.jp[^"#]+)"')
  foreach ($m in $matches) {
    $n = Normalize-Url $m.Groups[1].Value
    if ($n -and -not $visited.ContainsKey($n) -and $queue -notcontains $n) {
      $queue += $n
    }
  }
  Start-Sleep -Milliseconds 300
}

$manifest = @()
foreach ($url in ($pages.Keys | Sort-Object)) {
  $path = ([Uri]$url).AbsolutePath
  $local = if ($path -eq '/') { '/' } elseif ($path.EndsWith('/')) { $path.TrimEnd('/') } else { $path }
  $meta = Get-PageType $path
  $manifest += [PSCustomObject]@{
    source_url = $url
    local_route = $local
    page_title = $pages[$url]
    page_type = $meta.type
    parent_page = $meta.parent
    template_used = $meta.template
  }
}

$manifest | ConvertTo-Json -Depth 5 | Set-Content (Join-Path $PSScriptRoot 'route-manifest.json') -Encoding UTF8
Write-Host "`n=== TOTAL: $($manifest.Count) ==="

import type { NextConfig } from 'next';

const nextConfig: NextConfig = {
  images: {
    remotePatterns: [
      { protocol: 'https', hostname: 'coding-alive.jp', pathname: '/**' },
      { protocol: 'https', hostname: 'images.unsplash.com', pathname: '/**' },
    ],
  },
};

export default nextConfig;

const config = {
  plugins: {
    '@tailwindcss/postcss': {},
  },
};

export default config;

import fs from 'fs';
import path from 'path';

const ROOT = path.join(import.meta.dirname, '..');
const CACHE = path.join(import.meta.dirname, 'cache');
const manifest = JSON.parse(
  fs.readFileSync(path.join(import.meta.dirname, 'route-manifest.json'), 'utf8')
);

function cacheFileForUrl(url) {
  const safe = url.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 80);
  const exact = path.join(CACHE, `${safe}.html`);
  if (fs.existsSync(exact)) return exact;
  const files = fs.readdirSync(CACHE);
  const host = url.replace('https://coding-alive.jp', '').replace(/\/$/, '') || '/';
  const match = files.find((f) => f.includes(host.replace(/\//g, '_').slice(1, 40)));
  return match ? path.join(CACHE, match) : null;
}

function stripHtml(html) {
  return html
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function extractCards(html, type) {
  const items = [];
  const className =
    type === 'work' ? 'work-item' : type === 'blog' ? 'blog-item' : type === 'animation' ? 'animation-item' : 'staff-item';
  const re = new RegExp(`<div class="${className}"[\\s\\S]*?</div>\\s*</div>\\s*</div>`, 'gi');
  let block;
  const simpleRe =
    type === 'work'
      ? /<div class="work-item">([\s\S]*?)<\/div>\s*<\/div>\s*<\/div>/gi
      : type === 'blog'
        ? /<div class="blog-item">([\s\S]*?)<\/div>\s*<\/div>\s*<\/div>/gi
        : type === 'animation'
          ? /<div class="animation-item">([\s\S]*?)<\/div>\s*<\/div>/gi
          : /<div class="staff-item">([\s\S]*?)<\/div>\s*<\/div>/gi;

  while ((block = simpleRe.exec(html)) !== null) {
    const chunk = block[0];
    const hrefM = chunk.match(/href="(https:\/\/coding-alive\.jp\/[^"]+)"/);
    const titleM = chunk.match(/class="(?:work|blog|animation|staff)-title[^"]*"[^>]*>\s*<a[^>]*>([^<]+)</) ||
      chunk.match(/<a href="[^"]+">([^<]+)<\/a>/);
    const imgM = chunk.match(/data-src="([^"]+)"/) || chunk.match(/src="(https:\/\/coding-alive\.jp\/wp[^"]+)"/);
    const dateM = chunk.match(/class="[^"]*date[^"]*"[^>]*>([^<]+)</);
    const cats = [...chunk.matchAll(/class="(?:primary-cat|cat)[^"]*"[^>]*>([^<]*)</g)].map((m) => m[1].trim()).filter(Boolean);
    if (hrefM) {
      items.push({
        href: hrefM[1].replace('https://coding-alive.jp', ''),
        title: titleM ? titleM[1].trim() : 'Untitled',
        image: imgM ? imgM[1] : null,
        date: dateM ? dateM[1].trim() : null,
        categories: cats,
      });
    }
  }
  return items;
}

function extractDetail(html) {
  const titleM = html.match(/<h1[^>]*class="[^"]*entry-title[^"]*"[^>]*>([^<]+)</i) ||
    html.match(/<meta property="og:title" content="([^"]+)"/);
  const dateM = html.match(/<time[^>]*datetime="([^"]+)"/) || html.match(/class="date"[^>]*>([^<]+)</);
  const imgM = html.match(/<meta property="og:image" content="([^"]+)"/);
  const contentM = html.match(/<div class="entry-content[^"]*">([\s\S]*?)<\/div>\s*<(?:div|section) class="(?:entry-footer|related|c-section)/i) ||
    html.match(/<div class="post-content[^"]*">([\s\S]*?)<\/div>/i);
  const cats = [...html.matchAll(/<a href="https:\/\/coding-alive\.jp\/(?:work|blogcat|animation)[^"]+">([^<]+)<\/a>/g)]
    .slice(0, 6)
    .map((m) => m[1].trim());
  return {
    title: titleM ? titleM[1].replace(/\s*\|.*$/, '').trim() : '',
    date: dateM ? (dateM[1] || dateM[0]).trim() : null,
    image: imgM ? imgM[1] : null,
    categories: cats,
    bodyHtml: contentM ? contentM[1].trim() : null,
    excerpt: contentM ? stripHtml(contentM[1]).slice(0, 280) : null,
  };
}

function extractFilters(html) {
  const filters = [];
  const re = /<li class="[^"]*"><a href="(https:\/\/coding-alive\.jp\/[^"]+)"[^>]*>([^<]*)</gi;
  let m;
  while ((m = re.exec(html)) !== null) {
    if (m[1].includes('cat') || m[1].includes('/work/') || m[1].includes('/animation')) {
      filters.push({ href: m[1].replace('https://coding-alive.jp', ''), label: m[2].trim() });
    }
  }
  return filters.slice(0, 30);
}

const pages = manifest.map((route) => {
  const file = cacheFileForUrl(route.source_url);
  const html = file && fs.existsSync(file) ? fs.readFileSync(file, 'utf8') : '';
  const base = {
    route: route.local_route,
    sourceUrl: route.source_url,
    title: route.page_title,
    pageType: route.page_type,
    parentPage: route.parent_page,
    template: route.template_used,
  };

  if (!html) return { ...base, cards: [], filters: [], detail: null };

  let cards = [];
  if (route.template_used?.includes('work')) cards = extractCards(html, 'work');
  if (route.template_used?.includes('blog')) cards = extractCards(html, 'blog');
  if (route.template_used?.includes('animation')) cards = extractCards(html, 'animation');
  if (route.template_used === 'static-page' && route.local_route.includes('/staff')) {
    cards = extractCards(html, 'staff');
  }

  const detail = route.page_type === 'detail' ? extractDetail(html) : null;
  const filters = route.page_type === 'archive' || route.page_type === 'category' ? extractFilters(html) : [];

  return { ...base, cards, filters, detail };
});

fs.mkdirSync(path.join(ROOT, 'src', 'data'), { recursive: true });
fs.copyFileSync(
  path.join(import.meta.dirname, 'route-manifest.json'),
  path.join(ROOT, 'src', 'data', 'route-manifest.json')
);
fs.writeFileSync(path.join(ROOT, 'src', 'data', 'pages-index.json'), JSON.stringify(pages, null, 0));
console.log('Extracted', pages.length, 'pages');
console.log('With cards:', pages.filter((p) => p.cards?.length).length);
console.log('With detail:', pages.filter((p) => p.detail?.bodyHtml).length);

